];

const venues = $('Venue Config').all();
const venueSlug = venues[$runIndex]?.json?.slug ?? null;

return $input.all().map(item => ({
  json: { ...item.json, _venueSlug: venueSlug },
}));

function esc(v) {
  if (v === null || v === undefined) return 'NULL';
  return "'" + String(v).replace(/'/g, "''") + "'";
}

function stripHtml(html) {
  if (!html) return null;
  return html
    .replace(/<br\s*\/?>\s*/gi, '\n')
    .replace(/<\/li>/gi, '\n')
    .replace(/<\/p>/gi, '\n')
    .replace(/<[^>]+>/g, '')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&nbsp;/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim() || null;
}

const items = $input.all();
const results = [];

for (const item of items) {
  const ev = item.json;
  const venueSlug = ev._venueSlug || null;

  if (!ev.start?.dateTime) continue;
  const title = (ev.summary || '').trim();
  if (!title) continue;

  const description = stripHtml(ev.description);
  const titleLower = title.toLowerCase();
  const rawDesc = (ev.description || '');

  let tag = null;
  if (titleLower.includes('open mic') || titleLower.includes('open-mic')) {
    tag = 'open-mic';
  } else if (
    titleLower.includes('community jam') ||
    titleLower.includes('jam night') ||
    titleLower.includes('instant noodles')
  ) {
    tag = 'community-jam';
  } else if (
    titleLower.includes(' dj ') ||
    titleLower.startsWith('dj ') ||
    titleLower.includes('dance night') ||
    titleLower.includes('open house') ||
    titleLower.includes('ohc')
  ) {
    tag = 'dj-dance';
  } else if (
    titleLower.includes('final friday') ||
    titleLower.includes('live band') ||
    titleLower.includes('band night') ||
    titleLower.startsWith('bands')
  ) {
    tag = 'live-band';
  } else if (
    titleLower.includes('art walk') ||
    titleLower.includes('second saturday') ||
    titleLower.includes('2nd saturday') ||
    titleLower.includes('community')
  ) {
    tag = 'community-event';
  } else if (titleLower.includes('workshop') || titleLower.includes('class')) {
    tag = 'workshop-class';
  } else {
    const tagsMatch = rawDesc.match(/^tags:\s*(.+)$/im);
    if (tagsMatch) tag = tagsMatch[1].trim().split(',')[0].trim();
  }

  let ticketUrl = null;
  const ticketsMatch = rawDesc.match(/^tickets:\s*(https?:\/\/\S+)$/im);
  if (ticketsMatch) ticketUrl = ticketsMatch[1].trim();

  const googleEventId = ev.id;
  const startTime = ev.start.dateTime;
  const endTime = ev.end?.dateTime || null;
  const location = ev.location || null;

  const sql = `
INSERT INTO events (
  google_event_id, title, description, start_time, end_time,
  location, tag, ticket_url, venue, is_active, synced_at
) VALUES (
  ${esc(googleEventId)}, ${esc(title)}, ${esc(description)},
  ${esc(startTime)}::TIMESTAMPTZ, ${endTime === null ? 'NULL' : esc(endTime) + '::TIMESTAMPTZ'},
  ${esc(location)}, ${esc(tag)}, ${esc(ticketUrl)}, ${esc(venueSlug)}, true, NOW()
)
ON CONFLICT (google_event_id) DO UPDATE SET
  title       = EXCLUDED.title,
  description = EXCLUDED.description,
  start_time  = EXCLUDED.start_time,
  end_time    = EXCLUDED.end_time,
  location    = EXCLUDED.location,
  tag         = EXCLUDED.tag,
  ticket_url  = EXCLUDED.ticket_url,
  venue       = EXCLUDED.venue,
  is_active   = true,
  synced_at   = NOW()
RETURNING id, google_event_id, title, venue
`.trim();

  results.push({ json: { sql, title, tag, venue: venueSlug } });
}

return results;
